        [Description("Short title for the note")] string title,
        [Description("Body content of the note")] string body)
    {
        Notes.Add((title, body));
        Console.WriteLine($"  📝 Note saved: \"{title}\"");
        return $"Note #{Notes.Count} saved: {title}";
    }

    public string GetNotes()
    {
        if (Notes.Count == 0)
            return "No notes recorded yet.";

        return string.Join("\n\n", Notes.Select((n, i) =>
            $"--- Note #{i + 1}: {n.Title} ---\n{n.Body}"));
    }
}

