+        "Searches the web for a query and returns a list of result snippets."),
+    AIFunctionFactory.Create(notepad.AddNote, "add_note",
+        "Saves a research note with a title and body for later reference."),
+    AIFunctionFactory.Create(notepad.GetNotes, "get_notes",
+        "Returns all research notes taken so far."),
+};
+
+// --- Chat client setup -------------------------------------------------------
+
+var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
+    ?? throw new InvalidOperationException(
+        "Set the OPENAI_API_KEY environment variable before running.");
+
+var model = Environment.GetEnvironmentVariable("OPENAI_MODEL") ?? "gpt-4o-mini";
+
+IChatClient client = new ChatClientBuilder(
+        new OpenAIClient(apiKey).GetChatClient(model).AsIChatClient())
+    .UseFunctionInvocation()
+    .Build();
+
+// --- Agent loop --------------------------------------------------------------
+
+var topic = args.Length > 0
+    ? string.Join(' ', args)
+    : PromptUser("What topic should I research?");
+
+Console.WriteLine($"\n🔍 Researching: {topic}\n");
+
+List<ChatMessage> history =
+[
+    new(ChatRole.System, """
+        You are a research agent. Your goal is to thoroughly research the given
+        topic using the tools available to you.
+
+        Follow this process:
+        1. Search the web for information about the topic (2-3 searches with
+           different queries to get broad coverage).
+        2. As you find useful information, save key findings as notes using
+           the add_note tool.
+        3. After gathering enough information, retrieve your notes and write a
+           comprehensive summary of your findings.
+
+        Be thorough but concise. Cite specific facts and data where possible.
+        """),
+    new(ChatRole.User, $"Please research the following topic: {topic}"),
+];
+
+var options = new ChatOptions { Tools = [.. tools] };
+
+var response = await client.GetResponseAsync(history, options);
+
+Console.WriteLine("\n📋 Research Summary\n" + new string('─', 60));
+Console.WriteLine(response.Text);
+
+if (notepad.Notes.Count > 0)
+{
+    Console.WriteLine($"\n📝 {notepad.Notes.Count} note(s) were recorded during research.");
+}
+
+// --- Tool function definitions -----------------------------------------------
+
+static string WebSearch([Description("The search query")] string query)
+{
+    Console.WriteLine($"  🌐 Searching: \"{query}\"");
+
+    using var http = new HttpClient();
+    http.DefaultRequestHeaders.UserAgent.ParseAdd(
+        "ResearchAgent/1.0 (compatible; bot)");
+
+    try
+    {
+        // Use DuckDuckGo instant-answer API (no key required)
+        var url = $"https://api.duckduckgo.com/?q={Uri.EscapeDataString(query)}&format=json&no_html=1";
+        var json = http.GetStringAsync(url).GetAwaiter().GetResult();
+        var doc = System.Text.Json.JsonDocument.Parse(json);
+        var root = doc.RootElement;
+
+        var results = new List<string>();
+
+        // Abstract / summary
+        var abs = root.GetProperty("Abstract").GetString();
+        if (!string.IsNullOrWhiteSpace(abs))
+            results.Add($"Summary: {abs} (source: {root.GetProperty("AbstractSource").GetString()})");
+
+        // Related topics
+        if (root.TryGetProperty("RelatedTopics", out var topics))
+        {
+            foreach (var t in topics.EnumerateArray().Take(5))
+            {
+                var text = t.TryGetProperty("Text", out var tv) ? tv.GetString() : null;
+                if (!string.IsNullOrWhiteSpace(text))
+                    results.Add(text);
+            }
+        }
+
+        if (results.Count == 0)
+            results.Add($"No instant results found for \"{query}\". Try rephrasing.");
+
+        return string.Join("\n\n", results);
+    }
+    catch (Exception ex)
+    {
+        return $"Search failed: {ex.Message}";
+    }
+}
+
+static string PromptUser(string message)
+{
+    Console.Write($"{message} ");
+    return Console.ReadLine()?.Trim() ?? "artificial intelligence";
+}
+
+// --- Notepad helper ----------------------------------------------------------
+
+sealed class Notepad
+{
+    public List<(string Title, string Body)> Notes { get; } = [];
+
+    public string AddNote(
+        [Description("Short title for the note")] string title,
+        [Description("Body content of the note")] string body)
+    {
+        Notes.Add((title, body));
+        Console.WriteLine($"  📝 Note saved: \"{title}\"");
+        return $"Note #{Notes.Count} saved: {title}";
+    }
+
+    public string GetNotes()
+    {
+        if (Notes.Count == 0)
+            return "No notes recorded yet.";
+
+        return string.Join("\n\n", Notes.Select((n, i) =>
+            $"--- Note #{i + 1}: {n.Title} ---\n{n.Body}"));
+    }
+}
